### 第 5 步：创建 `ralph.config.json`

推荐从这份配置起步：

```json
{
  "prdPath": "./prd.json",
  "progressPath": "./progress.txt",
  "maxIterations": 10,
  "cooldownSeconds": 3,
  "permissionsMode": "full",
  "claude": {
    "maxTurns": 50
  },
  "prompts": {
    "agentInstructionPath": "./RALPH.md",
    "extraContextPaths": [
      "./CLAUDE.md"
    ],
    "extraInstructions": "",
    "strictSingleStory": true
  },
  "validation": {
    "checkGitCommit": true,
    "patchPrdPasses": true,
    "validatePrdSchema": true,
    "acceptanceCommands": {
      "typecheck": "npm run typecheck",
      "tests": "npm test",
      "browser": "npm run test:browser"
    }
  }
}
```
